def carregar_tudo(store: CalendarStore, ano: int = 2026):
    """Carrega todos os feriados no banco SQLite."""
    nac = [{"data": d, "descricao": desc, "tipo": "nacional", "fonte": "Leis Federais", "confianca": "high"} for d, desc in NACIONAIS_2026]
    store.inserir_lote(nac)
    print(f"  Nacionais: {len(nac)}")

    rec = [{"data": d, "descricao": desc, "tipo": "recesso", "fonte": "CPC art. 220", "confianca": "high"} for d, desc in RECESSO_2026]
    store.inserir_lote(rec)
    print(f"  Recesso: {len(rec)} dias")

    for uf, feriados in ESTADUAIS_2026.items():
        est = [{"data": d, "descricao": desc, "tipo": "estadual_tj", "uf": uf, "tribunal": f"TJ{uf}", "fonte": "Lei Estadual", "confianca": "high"} for d, desc in feriados]
        store.inserir_lote(est)
    print(f"  Estaduais: {sum(len(v) for v in ESTADUAIS_2026.values())} (27 UFs)")

    for tj, info in SUSPENSOES_TJ.items():
        uf = tj.replace("TJ", "")
        susp = [{"data": d, "descricao": desc, "tipo": "suspensao_tj", "uf": uf, "tribunal": tj, "fonte": info["fonte"], "confianca": "high"} for d, desc in info["suspensoes"]]
        store.inserir_lote(susp)
        store.registrar_fonte(tj, info["fonte"], ano, len(susp), info.get("url", ""))
    print(f"  Suspensoes TJ: {list(SUSPENSOES_TJ.keys())}")

    for tj, comarcas_dict in MUNICIPAIS_POR_TJ.items():
        info = FONTES_TJ[tj]
        total_tj = 0
        for comarca_processo, feriados in comarcas_dict.items():
            mun = [{"data": d, "descricao": desc, "tipo": "municipal_forense", "uf": info["uf"], "comarca": comarca_processo, "tribunal": tj, "fonte": info["fonte"], "confianca": info["confianca"]} for d, desc in feriados]
            store.inserir_lote(mun)
            total_tj += len(feriados)
        store.registrar_fonte(tj, info["fonte"], ano, total_tj)
        print(f"  {tj}: {len(comarcas_dict)} comarcas, {total_tj} feriados [{info['confianca']}]")

    print(f"\n  Carregamento completo.")


if __name__ == "__main__":
    parser = argparse.ArgumentParser(description="Carrega feriados forenses no banco")
    parser.add_argument("--db", default="calendar_v2.db")
    parser.add_argument("--ano", type=int, default=2026)
    parser.add_argument("--limpar", action="store_true")
    args = parser.parse_args()

    store = CalendarStore(args.db)
    if args.limpar:
        store.limpar_ano(args.ano)
    print(f"Carregando feriados forenses {args.ano}...\n")
    carregar_tudo(store, args.ano)

    contagem = store.contar(args.ano)
    print(f"\n--- ESTATISTICAS ---")
    for tipo, total in sorted(contagem.items()):
        print(f"  {tipo}: {total}")
    print(f"  TOTAL: {sum(contagem.values())}")

    for uf in ["SP", "MG", "PR", "SC", "MT", "MS", "RS", "GO"]:
        c = store.listar_comarcas(uf)
        if c:
            print(f"  {uf}: {len(c)} comarcas")
    store.close()
